using Payments;

namespace PaymentGateway.Tests;

[TestClass]
public class ChargeTests
{
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new Payments.PaymentGateway();

    // --- Happy-path ---

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndAmount_ReturnsSuccessWithChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_MinimumAmount_Succeeds()
    {
        var result = await _gateway.ChargeAsync("tok_valid", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_Succeeds()
    {
        var result = await _gateway.ChargeAsync("tok_valid", 999_999.99m);

        Assert.IsTrue(result.Success);
    }

    // --- Invalid arguments ---

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task ChargeAsync_NullToken_ThrowsArgumentException()
    {
        await _gateway.ChargeAsync(null!, 10m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task ChargeAsync_EmptyToken_ThrowsArgumentException()
    {
        await _gateway.ChargeAsync("", 10m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task ChargeAsync_WhitespaceToken_ThrowsArgumentException()
    {
        await _gateway.ChargeAsync("   ", 10m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentOutOfRangeException()
    {
        await _gateway.ChargeAsync("tok_valid", 0m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentOutOfRangeException()
    {
        await _gateway.ChargeAsync("tok_valid", -5m);
    }

    // --- Declined card ---

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 10m);

        Assert.IsFalse(result.Success);
    }

    // --- Idempotency ---

    [TestMethod]
    public async Task ChargeAsync_TwoCalls_ReturnDistinctChargeIds()
    {
        var r1 = await _gateway.ChargeAsync("tok_valid", 10m);
        var r2 = await _gateway.ChargeAsync("tok_valid", 10m);

        Assert.AreNotEqual(r1.ChargeId, r2.ChargeId);
    }
}

[TestClass]
public class RefundTests
{
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new Payments.PaymentGateway();

    // --- Happy-path ---

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessWithRefundId()
    {
        var result = await _gateway.RefundAsync("ch_valid");

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.RefundId));
    }

    // --- Invalid arguments ---

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentException()
    {
        await _gateway.RefundAsync(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await _gateway.RefundAsync("");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task RefundAsync_WhitespaceChargeId_ThrowsArgumentException()
    {
        await _gateway.RefundAsync("   ");
    }

    // --- Non-existent charge ---

    [TestMethod]
    public async Task RefundAsync_NonExistentChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_nonexistent");

        Assert.IsFalse(result.Success);
    }

    // --- Double refund ---

    [TestMethod]
    public async Task RefundAsync_SameChargeIdTwice_SecondCallReturnsFailure()
    {
        var first = await _gateway.RefundAsync("ch_valid");
        var second = await _gateway.RefundAsync("ch_valid");

        Assert.IsTrue(first.Success);
        Assert.IsFalse(second.Success, "A charge should not be refundable twice.");
    }
}

